SELECT d.id, d.name doctorName, d.title, d.avatar, h.name hospitalName, dt.name departmentName, dt.id departmentId FROM t_doctor d INNER JOIN t_hospital h ON d.hospital_id = h.id INNER JOIN t_department dt ON d.department_id = dt.id WHERE d.hospital_id = #{hospitalId}
AND d.department_id = #{departmentId}
ORDER BY d.follow_count DESC

SELECT d.id, d.name doctorName, d.title, d.avatar, d.hospital_id hospitalId, h.name hospitalName, dt.id departmentId, dt.name departmentName FROM t_doctor d INNER JOIN t_hospital h ON d.hospital_id = h.id INNER JOIN t_department dt ON d.department_id = dt.id WHERE d.status = 1
AND d.hospital_id = #{query.hospitalId}
AND d.department_id IN
#{deptId}
AND d.online_status = #{query.onlineStatus}
AND (d.name LIKE CONCAT('%', #{query.expertise}, '%') OR d.expertise LIKE CONCAT('%', #{query.expertise}, '%'))
ORDER BY d.follow_count DESC
